				ydL3Msg    = "오류:권하실적위치 없음";	
//			} else if ("XX".equals(ydDnWrLoc.substring(0, 2))) {
//				ydL3HdRsCd = "DN04";
//				ydL3Msg    = "오류:권하실적위치 이상";
