			String msgId        = commUtils.getMsgId(rcvMsg); //EAI, JMS, HTTP(출하관리 등) 수신 전문 I/F ID
			String ydEqpId     	= commUtils.trim(rcvMsg.getFieldString("YD_EQP_ID"));     		//설비ID
