	    			jrYdMsg.setResultMsg(methodNm);	//Log Method Name

	    			jrYdMsg.setField("JMS_TC_CD"         	, "A7YML007"); 					//JMSTC코드
	    			jrYdMsg.setField("JMS_TC_CREATE_DDTT"	, commUtils.getDateTime14()); 	//JMSTC생성일시
