	    		//------------------------------------------------------------------------
	    		// 본래 권하위치가 차량 또는 대차에서 일반야드로 권하위치를 변경하는경우
	    		//------------------------------------------------------------------------
	    		String szChgEqpGp    = ydChgDnWoLoc.substring(2,4); 
