	public JDTORecord rcvMHMI310(JDTORecord rcvMsg) throws DAOException {
		String methodNm = "1냉연 설비상태정보[BCoilL2RcvSeEJB.rcvMHMI310] < " + rcvMsg.getResultMsg();
		String logId = rcvMsg.getResultCode();
		
		JDTORecord jrRtn = null;	//전문 Return
		try {
			commUtils.printLog(logId, methodNm, "S+");
			
			//수신 항목 값
			String msgId           = commUtils.getMsgId(rcvMsg); //EAI, JMS, HTTP(출하관리 등) 수신 전문 I/F ID
			String sOCCURDATE      = commUtils.trim(rcvMsg.getFieldString("OCCURDATE"     )); //발생일자    
			String sWORK_EXP       = commUtils.trim(rcvMsg.getFieldString("WORK_EXP"      )); //작업근조    
			String sWORK_PLANT     = commUtils.trim(rcvMsg.getFieldString("WORK_PLANT"    )); //작업공장    
			String sWORK_PROC      = commUtils.trim(rcvMsg.getFieldString("WORK_PROC"     )); //작업공정    
			String sTC_COUNT       = commUtils.trim(rcvMsg.getFieldString("TC_COUNT"      )); //전문COUNT   
			String sTC_DEMAND_GP   = commUtils.trim(rcvMsg.getFieldString("TC_DEMAND_GP"  )); //전문요구구분
			String sEXTRA_ITEM     = commUtils.trim(rcvMsg.getFieldString("EXTRA_ITEM"    )); //여분항목    
			String sEQUIP_CD       = commUtils.trim(rcvMsg.getFieldString("EQUIP_CD"      )); //설비코드    
			String sOPERATION_STAT = commUtils.trim(rcvMsg.getFieldString("OPERATION_STAT")); //운전상태
			String sEQUIP_STAT     = commUtils.trim(rcvMsg.getFieldString("EQUIP_STAT"    )); //설비상태

			//methodNm = msgId.substring(0, 2) + methodNm;
			
			/**********************************************************
			* 1. 수신 항목 값 Check
			**********************************************************/
			if (sEQUIP_STAT.length() == 0) {
				throw new Exception("설비상태 길이가 0");
			}

			/**********************************************************
			* 2. 설비 SETTING
			**********************************************************/
			JDTORecord jrecord = JDTORecordFactory.getInstance().create();
			
			if (YmConstant.TRO_REC_0.equals(sEQUIP_STAT)) { 			//고장
				/*
				UPDATE TB_YM_EQUIP
				   SET CARLOAD_ASSIGN_YN     = 'Y'
				     , HMI_STAT              = :V_HMI_STAT --HMI 상태
				     , CARLOAD_SCH_WORK_KIND = :V_CARLOAD_SCH_WORK_KIND --상차 스케줄 작업종류
				 WHERE EQUIP_GP = :V_EQUIP_GP --설비구분
				 */
				jrecord.setField("HMI_STAT"             , "C");
				jrecord.setField("CARLOAD_SCH_WORK_KIND", "CTFL");
				jrecord.setField("EQUIP_GP"             , "3XTC02");
				commDao.update(jrecord, "com.inisteel.cim.ym.bcommon.dao.YmCommDAO.updateLoadSchOfVicCar");

	        } else if (YmConstant.TRO_REC_1.equals(sEQUIP_STAT)) { 	//복구	         
	        	/*
				UPDATE TB_YM_EQUIP
				   SET HMI_STAT = :V_HMI_STAT --HMI 상태
				     , MODIFIER = 'SYSTEM'
				     , MOD_DDTT = SYSDATE
				 WHERE EQUIP_GP = :V_EQUIP_GP --설비구분
	        	 */
	        	jrecord.setField("HMI_STAT"             , "O");
				jrecord.setField("EQUIP_GP"             , "3XTC02");
				commDao.update(jrecord, "com.inisteel.cim.ym.bcommon.dao.YmCommDAO.updateHMIModeOfEquip");
	        }

			commUtils.printLog(logId, methodNm, "S-");

			return jrRtn;
		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, methodNm, e));
		}

	}	
	
	
