			jrYdMsg.setResultMsg(methodNm);	//Log Method Name

			jrYdMsg.setField("WORK_EXP", YmCommUtils.getWorkParty());   
			jrYdMsg.setField("COIL_NO" , sCOILNO);				
			
			//크레인스케줄 기동
