						jrL2Crn.setField("OTHER_FROM_XAXIS"       	, commUtils.trim(jrL2CrnStat.getFieldString("FROM_XAXIS" ))); 
						jrL2Crn.setField("OTHER_TO_XAXIS"         	, commUtils.trim(jrL2CrnStat.getFieldString("TO_XAXIS" )));
						jrL2Crn.setField("OTHER_DIR_GP"         	, commUtils.trim(jrL2CrnStat.getFieldString("OTHER_DIR_GP" )));
						
