							//recPara1.setField("TO_CONTENT"   , "L2 DB LINK 이상발생");
							//YmCommUtils.updSmsMsgSend(recPara1); // SMS 송신 
							
							// 2025.09.29 SMS송신 -> 카카오톡 전환
		                    MessageSenderTalk    sender = new MessageSenderTalk();		
		                    String subJect = "SmS 전송";
